  screen.level(13); screen.rect(sx + 1, sy + 3, 5, 4); screen.fill()
  screen.level(11); screen.pixel(sx,     sy + 4); screen.pixel(sx + 6, sy + 4)                    -- waist notches
  screen.pixel(sx,     sy + 5); screen.pixel(sx + 6, sy + 5); screen.fill()
