      "[Miel]    Even out here, the small things sing. I'd forgotten.",
    }},
  },
  -- Sunward Coast fire (mainland 53,8).
  ["1:53:8"] = {
    {requires = {"bard", "mage"}, lines = {
      "(Alder tunes the lute by the fire's pop and crackle.)",
