  screen.level(13); screen.rect(sx + 2, sy + 1, 4, 2); screen.fill()
  screen.level(0); screen.pixel(sx + 3, sy + 2); screen.pixel(sx + 4, sy + 2); screen.fill()
  -- jaw shadow
  screen.level(7); screen.pixel(sx + 2, sy + 3); screen.pixel(sx + 5, sy + 3); screen.fill()
  -- tunic
  screen.level(7); screen.rect(sx + 1, sy + 3, 6, 3); screen.fill()
  screen.level(11); screen.rect(sx + 3, sy + 4, 2, 1); screen.fill()  -- belt buckle
  -- half-laced boots (one done, one not)
  screen.level(3); screen.rect(sx + 1, sy + 6, 2, 2); screen.fill()   -- laced
  screen.level(5); screen.rect(sx + 5, sy + 7, 2, 1); screen.fill()   -- unlaced
  screen.level(11); screen.pixel(sx + 5, sy + 6); screen.fill()
end

-- Borin: young recruit, oversized spear, anxious posture.
NPC_SPRITES.Borin = function(sx, sy)
  -- spear (tall, leaning slightly)
  screen.level(7); screen.rect(sx + 6, sy - 1, 1, 7); screen.fill()
  screen.level(13); screen.pixel(sx + 6, sy - 2); screen.fill()
  -- thin shoulders
  screen.level(8); screen.rect(sx + 2, sy + 3, 4, 4); screen.fill()
  -- face (pale, wide eyes)
  screen.level(13); screen.rect(sx + 2, sy + 1, 4, 2); screen.fill()
  screen.level(15); screen.pixel(sx + 3, sy + 2); screen.pixel(sx + 4, sy + 2); screen.fill()  -- wide-eyed
  -- shaky hand (animated)
  if (tick % 8) < 4 then
    screen.level(11); screen.pixel(sx + 5, sy + 5); screen.fill()
  else
    screen.level(11); screen.pixel(sx + 6, sy + 5); screen.fill()
  end
  -- boots
  screen.level(3); screen.rect(sx + 2, sy + 7, 1, 1); screen.fill()
  screen.level(3); screen.rect(sx + 5, sy + 7, 1, 1); screen.fill()
end

-- HealerYmra: long apron robe, hair tied back, basin of water in hand.
NPC_SPRITES.HealerYmra = function(sx, sy)
  -- tied-back hair (dark)
  screen.level(3); screen.rect(sx + 2, sy, 4, 1); screen.fill()
  screen.level(3); screen.pixel(sx + 1, sy + 1); screen.fill()        -- nape strand
  -- face
  screen.level(13); screen.rect(sx + 2, sy + 1, 4, 2); screen.fill()
  screen.level(0); screen.pixel(sx + 3, sy + 2); screen.pixel(sx + 4, sy + 2); screen.fill()
  -- white apron robe
  screen.level(15); screen.rect(sx + 1, sy + 3, 6, 5); screen.fill()
  screen.level(11); screen.move(sx + 4, sy + 3); screen.line(sx + 4, sy + 7); screen.stroke()  -- apron seam
  -- red cross at chest
  screen.level(0); screen.rect(sx + 3, sy + 4, 2, 1); screen.fill()
  screen.level(0); screen.pixel(sx + 4, sy + 5); screen.fill()
  -- basin in hand (right)
  screen.level(7); screen.rect(sx + 6, sy + 4, 1, 1); screen.fill()
end

-- WoundedGuard: lying flat (most of the sprite is bedding + face).
NPC_SPRITES.WoundedGuard = function(sx, sy)
  -- bedsheet under
  screen.level(11); screen.rect(sx, sy + 5, 8, 3); screen.fill()
  screen.level(7); screen.rect(sx, sy + 7, 8, 1); screen.fill()
  -- body (lying flat, lengthwise)
  screen.level(5); screen.rect(sx + 1, sy + 5, 6, 1); screen.fill()
  -- face (only the head pokes out — small at top)
  screen.level(13); screen.rect(sx + 3, sy + 3, 2, 2); screen.fill()
  screen.level(0); screen.pixel(sx + 3, sy + 4); screen.pixel(sx + 4, sy + 4); screen.fill()
  -- bandage across head (animated faint pulse so it reads as "alive")
  screen.level((tick % 32) < 16 and 15 or 13)
  screen.rect(sx + 3, sy + 3, 2, 1); screen.fill()
  -- bloody arm-bandage at midbody
  screen.level(8); screen.pixel(sx + 6, sy + 5); screen.pixel(sx + 7, sy + 5); screen.fill()
end

-- ============================================================ DRAWING — STATES

-- Pixel offsets that center an interior map within the 128x64 viewport.
-- Returns (0,0) for maps that meet or exceed viewport dimensions
-- (overworld, throne hall, etc.). When non-zero, the surrounding margin
-- is painted with a static musical-staff backdrop and the room is
-- inset by (ox, oy).
-- Global (not local) to dodge the 200-locals-per-main-chunk Lua cap.
function interior_view_offset()
  local ox = math.max(0, math.floor((VIEW_W - MAP_W) / 2) * TILE)
  local oy = math.max(0, math.floor((VIEW_H - MAP_H) / 2) * TILE)
  return ox, oy
end

-- Static musical-staff wallpaper for the margin around a centered
-- interior map. Five horizontal lines plus a small treble-clef glyph
-- anchored in the left margin. Drawn before tiles so opaque room walls
-- cover it where they overlap; only the off-room strips show.
function draw_staff_backdrop(ox, oy)
  screen.level(0); screen.rect(0, 0, 128, 64); screen.fill()
  screen.level(3)
  local STAFF_YS = {12, 22, 32, 42, 52}
  for _, y in ipairs(STAFF_YS) do
    screen.move(0, y); screen.line(128, y); screen.stroke()
  end
  if ox > 0 then
    -- 9-wide pixel-grid treble clef centered horizontally in the left
    -- margin. Curl at top, big loop in the middle, tail at the bottom.
    local CLEF = {
      "   ###   ",
      "  #   #  ",
      " #     # ",
      " #     # ",
      " #    #  ",
      " #   #   ",
      "  # #    ",
      "   #     ",
      "  ###    ",
      " #  ##   ",
      " #   ##  ",
      "##    ## ",
      "##  # ## ",
      "##  # ## ",
      " #  # #  ",
      "  ##  #  ",
      "    ##   ",
      "    #    ",
      "    #    ",
      "   ##    ",
      "  ## ##  ",
      " ##    # ",
      " #     # ",
      "  ## ##  ",
      "   ###   ",
    }
    local cw = #CLEF[1]
    local cx = math.max(1, math.floor((ox - cw) / 2))
    local cy = math.max(2, math.floor((64 - #CLEF) / 2))
    screen.level(9)
    for row = 1, #CLEF do
      local line = CLEF[row]
      for col = 1, #line do
        if line:sub(col, col) == "#" then
          screen.pixel(cx + col - 1, cy + row - 1)
        end
      end
    end
    screen.fill()
  end
end

local function draw_overworld()
  local view_ox, view_oy = interior_view_offset()
  local centered = (view_ox > 0) or (view_oy > 0)
  if centered then draw_staff_backdrop(view_ox, view_oy) end
  for vy = 0, VIEW_H - 1 do
    for vx = 0, VIEW_W - 1 do
      local tx = cam.x + vx
      local ty = cam.y + vy
      if centered and (tx < 1 or tx > MAP_W or ty < 1 or ty > MAP_H) then
        goto next_tile
      end
      local t = tile_at(tx, ty)
      local sx = vx * TILE + view_ox
      local sy = vy * TILE + view_oy
      -- Inside-an-interior overrides:
      --   inn/shop (5/6) → wood planks for floor + themed walls
      --   cave1-5 (7-11) → cave floor for floor
      if (current_map_id == 5 or current_map_id == 6 or current_map_id == 15 or current_map_id == 16
          or current_map_id == 17 or current_map_id == 18 or current_map_id == 19
          or current_map_id == 20 or current_map_id == 21
          or current_map_id == 27 or current_map_id == 28
          or current_map_id == 29 or current_map_id == 30
          or current_map_id == 31 or current_map_id == 33
          or current_map_id == 34) and t == 0 then
        TILE_DRAW.floor(sx, sy)
      elseif current_map_id == 23 and t == 0 then
        -- Lirael Ruins: ash-covered scorched stone. Drawn as dim stone
        -- with sparse light flecks (per-tile-stable so it doesn't shimmer).
        screen.level(2); screen.rect(sx, sy, 8, 8); screen.fill()
        local seed = (tx * 17 + ty * 31) % 32
        if seed < 6 then
          screen.level(4); screen.pixel(sx + (seed % 7), sy + ((seed * 3) % 7))
          screen.fill()
        end
        if seed > 24 then
          screen.level(3); screen.pixel(sx + 7 - (seed % 7), sy + 7 - ((seed * 5) % 7))
          screen.fill()
        end
      elseif current_map_id == 23 and t == 4 then
        -- Ruined wall block — broken stone with chipped edge.
        screen.level(5); screen.rect(sx, sy, 8, 8); screen.fill()
        screen.level(3); screen.rect(sx, sy + 4, 8, 1); screen.fill()
        screen.level(2); screen.pixel(sx + 1, sy + 1); screen.pixel(sx + 6, sy + 6); screen.fill()
        local seed = (tx * 13 + ty * 7) % 8
        if seed < 3 then
          screen.level(0); screen.rect(sx + (seed * 2), sy + 7, 2, 1); screen.fill()
        end
      elseif current_map_id == 24 and t == 0 then
        -- Observatory floor — deep blue-black polished stone. Faint
        -- starfield: a few stable bright pixels that don't shimmer.
        screen.level(1); screen.rect(sx, sy, 8, 8); screen.fill()
        local seed = (tx * 19 + ty * 11) % 64
        if seed < 4 then
          screen.level(11); screen.pixel(sx + (seed % 7), sy + ((seed * 5) % 7))
          screen.fill()
        elseif seed < 8 then
          screen.level(7); screen.pixel(sx + ((seed + 3) % 7), sy + ((seed * 3) % 7))
          screen.fill()
        end
      elseif current_map_id == 24 and t == 4 then
        -- Observatory wall — dark with brass-fitting glints.
        screen.level(3); screen.rect(sx, sy, 8, 8); screen.fill()
        screen.level(5); screen.rect(sx, sy, 8, 1); screen.fill()
        screen.level(5); screen.rect(sx, sy + 7, 8, 1); screen.fill()
        local seed = (tx * 7 + ty * 13) % 16
        if seed < 3 then
          screen.level(11); screen.pixel(sx + 4, sy + 4); screen.fill()
        end
      elseif (current_map_id == 5 or current_map_id == 17 or current_map_id == 18 or current_map_id == 19 or current_map_id == 20
              or current_map_id == 27 or current_map_id == 28
              or current_map_id == 29 or current_map_id == 30
              or current_map_id == 31 or current_map_id == 32
              or current_map_id == 33 or current_map_id == 34) and t == 4 then
        TILE_DRAW.inn_wall(sx, sy, tx + ty * MAP_W)
      elseif (current_map_id == 6 or current_map_id == 15 or current_map_id == 16) and t == 4 then
        TILE_DRAW.shop_wall(sx, sy, tx + ty * MAP_W)
      elseif (current_map_id == 7 or current_map_id == 8 or current_map_id == 9
              or current_map_id == 10 or current_map_id == 11
              or current_map_id == 12 or current_map_id == 13
              or current_map_id == 14) and t == 0 then
        TILE_DRAW.cavefloor(sx, sy, tx + ty * MAP_W)
      else
        local fn = TILE_DRAW[t] or TILE_DRAW[0]
        if t == 3 or t == 6 or t == 7 or t == 9 or t == 11 or t == 14 or t == 16 or t == 18 or t == 19 or t == 20 or t == 24 or t == 27 or t == 30 or t == 32 or t == 36 or t == 38 or t == 39 or t == 41 or t == 43 or t == 52 or t == 53 or t == 54 or t == 55 or t == 56 or t == 57 or t == 58 or t == 62 then fn(sx, sy, tick)
        elseif t == 0 or t == 8 then fn(sx, sy, tx + ty * MAP_W)
        else fn(sx, sy)
        end
      end
      ::next_tile::
    end
  end

  -- NPCs face the camera (down) regardless of where the player is facing,
  -- since some NPC sprites (engineer, mathwiz) use the player.facing
  -- dispatcher when rendered.
  local saved_facing_npc = player.facing
  player.facing = "down"
  for _, n in ipairs(npcs) do
    if n.x >= cam.x and n.x < cam.x + VIEW_W
       and n.y >= cam.y and n.y < cam.y + VIEW_H
       and npc_visible(n) then
      local fn = NPC_SPRITES[n.name] or draw_npc_at
      -- subtle idle bob: each NPC breathes 1px out of phase with the others
      local bob = (((tick + n.x * 7 + n.y * 3) % 32) < 16) and 0 or 1
      fn((n.x - cam.x) * TILE + view_ox, (n.y - cam.y) * TILE - bob + view_oy)
    end
  end
  player.facing = saved_facing_npc

  -- NPC barks: small text bubble above the NPC sprite, fades out over
  -- 90 ticks. Match each bark to its source NPC by name; skip any
  -- whose NPC is offscreen or no longer visible. Prune expired entries.
  if CONTENT.barks and #CONTENT.barks > 0 then
    screen.font_face(25); screen.font_size(6)
    for i = #CONTENT.barks, 1, -1 do
      local b = CONTENT.barks[i]
      local age = tick - b.t
      if age > 90 then
        table.remove(CONTENT.barks, i)
      else
        -- find NPC by name to get current position
        local src
        for _, n in ipairs(npcs) do
          if n.name == b.name then src = n; break end
        end
        if src and src.x >= cam.x and src.x < cam.x + VIEW_W
           and src.y >= cam.y and src.y < cam.y + VIEW_H
           and npc_visible(src) then
          local sx = (src.x - cam.x) * TILE + 4 + view_ox
          local sy = (src.y - cam.y) * TILE - 4 + view_oy
          local w = math.min(110, #b.line * 4 + 4)
          -- bubble background (dark)
          screen.level(0); screen.rect(sx - w / 2, sy - 6, w, 7); screen.fill()
          -- bubble border + tail (fades with age)
          local lev = math.max(2, 11 - math.floor(age / 12))
          screen.level(lev); screen.rect(sx - w / 2, sy - 6, w, 7); screen.stroke()
          screen.pixel(sx, sy + 1); screen.pixel(sx, sy + 2); screen.fill()
          -- text
          screen.level(math.max(2, 15 - math.floor(age / 8)))
          screen.move(sx, sy - 1); screen.text_center(b.line)
        end
      end
    end
    screen.font_face(1); screen.font_size(8)
  end

  -- campfires (always visible — they don't get used up)
  for _, f in ipairs(CONTENT.campfires) do
    if f.map == current_map_id
       and f.x >= cam.x and f.x < cam.x + VIEW_W
       and f.y >= cam.y and f.y < cam.y + VIEW_H then
      local sx, sy = (f.x - cam.x) * TILE + view_ox, (f.y - cam.y) * TILE + view_oy
      -- log base
      screen.level(5)
      screen.rect(sx + 1, sy + 6, 6, 1); screen.fill()
      screen.level(7)
      screen.rect(sx + 2, sy + 5, 4, 1); screen.fill()
      -- flame (animated)
      local f1 = (tick % 4 < 2) and 0 or 1
      screen.level(15)
      screen.move(sx + 4, sy + 1 + f1)
      screen.line(sx + 2, sy + 5)
      screen.line(sx + 6, sy + 5)
      screen.close(); screen.fill()
      screen.level(11)
      screen.pixel(sx + 4, sy + 3 + f1); screen.fill()
    end
  end
  -- treasure chests on the current map (only render unopened ones)
  for _, c in ipairs(CONTENT.chests) do
    if c.map == current_map_id and not CONTENT.opened[c.id]
       and c.x >= cam.x and c.x < cam.x + VIEW_W
       and c.y >= cam.y and c.y < cam.y + VIEW_H then
      local sx, sy = (c.x - cam.x) * TILE + view_ox, (c.y - cam.y) * TILE + view_oy
      -- gold chest, lid + body, with a tiny shimmer
      screen.level(11); screen.rect(sx + 1, sy + 3, 6, 4); screen.fill()
      screen.level(15); screen.rect(sx + 1, sy + 2, 6, 1); screen.fill()  -- lid
      screen.level(0);  screen.pixel(sx + 4, sy + 4); screen.fill()       -- keyhole
      if (tick % 8) < 4 then
        screen.level(15); screen.pixel(sx + 5, sy + 1); screen.fill()
      else
        screen.level(13); screen.pixel(sx + 2, sy + 1); screen.fill()
      end
    end
  end

  -- Scripted scene actors render between map sprites and the player.
  if SCENE and SCENE.active and SCENE.draw then SCENE.draw() end

  if not (SCENE and SCENE.active and SCENE.hide_player) then
    draw_player_at((player.x - cam.x) * TILE + view_ox, (player.y - cam.y) * TILE + view_oy)
  end

  -- prompt: talk OR enter cave OR enter inn
  local fnpc = find_facing_npc()
  local fdx, fdy = facing_offset()
  local ftile = tile_at(player.x + fdx, player.y + fdy)
  if fnpc and (tick % 8) < 5 then
    screen.level(15)
    screen.move(64, 60)
    -- Prompt verb varies by NPC kind:
    --   kind = "object" → "check"  (stones, plaques, orrery, graves)
    --   kind = "pet"    → "pet"    (cats, falcons, birds)
    --   default         → "talk"
    local verb = "talk"
    if fnpc.kind == "object" then verb = "check"
    elseif fnpc.kind == "pet" then verb = "pet" end
    screen.text_center("A: " .. verb)
  elseif ftile == 5 and (tick % 8) < 5 then
    screen.level(15)
    screen.move(64, 60)
    screen.text_center("walk in to rest")
  elseif ftile == 6 and (tick % 8) < 5 then
    screen.level(15)
    screen.move(64, 60)
    local s = cave_state[1]
    if s.cleared then screen.text_center("the cave hums softly")
    elseif s.victories >= BOSS_THRESHOLD then screen.text_center("the air thickens...")
    else screen.text_center("walk in to fight (" .. s.victories .. "/" .. BOSS_THRESHOLD .. ")") end
  elseif ftile == 7 and (tick % 8) < 5 then
    screen.level(15)
    screen.move(64, 60)
    local s = cave_state[2]
    if s.cleared then screen.text_center("the woods are still")
    elseif s.victories >= BOSS_THRESHOLD then screen.text_center("the trees stop swaying...")
    else screen.text_center("enter the deep wood (" .. s.victories .. "/" .. BOSS_THRESHOLD .. ")") end
  elseif ftile == 9 and (tick % 8) < 5 then
    screen.level(15)
    screen.move(64, 60)
    local s = cave_state[3]
    if s.cleared then screen.text_center("the tide breathes calm")
    elseif s.victories >= BOSS_THRESHOLD then screen.text_center("the water rises...")
    else screen.text_center("descend the cavern (" .. s.victories .. "/" .. BOSS_THRESHOLD .. ")") end
  elseif ftile == 11 and (tick % 8) < 5 then
    screen.level(15)
    screen.move(64, 60)
    local s = cave_state[4]
    if s.cleared then screen.text_center("the dunes whisper")
    elseif s.victories >= BOSS_THRESHOLD then screen.text_center("sand stirs...")
    else screen.text_center("enter the glass cave (" .. s.victories .. "/" .. BOSS_THRESHOLD .. ")") end
  elseif ftile == 16 and (tick % 8) < 5 then
    screen.level(15)
    screen.move(64, 60)
    local s = cave_state[5]
    if s.cleared then screen.text_center("the wind quiets")
    elseif s.victories >= BOSS_THRESHOLD then screen.text_center("the cold deepens...")
    else screen.text_center("enter the ice grotto (" .. s.victories .. "/" .. BOSS_THRESHOLD .. ")") end
  elseif ftile == 15 and (tick % 8) < 5 then
    screen.level(15)
    screen.move(64, 60)
    screen.text_center("cross the pass")
  elseif ftile == 10 and (tick % 8) < 5 then
    screen.level(15)
    screen.move(64, 60)
    screen.text_center("set sail")
  end

  -- region environmental overlay (atmospheric particles per region)
  local region = get_region(player.x)
  if region == "woods" then
    -- falling leaves drifting downward
    for i = 1, 4 do
      local lx = (i * 41 + tick * 2) % 128
      local ly = (i * 17 + tick) % 64
      screen.level(7)
      screen.pixel(lx, ly)
    end
    -- dim mist stipple
    screen.level(2)
    for i = 0, 9 do
      screen.pixel((i * 13 + tick) % 128, (i * 7 + 3) % 64)
    end
  elseif region == "coast" then
    -- sun rays from upper-right corner
    screen.level(13)
    for i = 1, 5 do
      local x = 124 - i * 4
      screen.pixel(x, i * 2)
      screen.pixel(x - 1, i * 2 + 1)
    end
    -- shimmer sparkles
    for i = 1, 3 do
      local sx = (i * 53 + tick * 3) % 128
      local sy = (i * 11 + tick) % 28
      if (tick + i * 7) % 8 < 3 then
        screen.level(15)
        screen.pixel(sx, sy)
      end
    end
  end

  -- active voice indicator (top-right) — which character the right stick filters
  if party[active] then
    screen.level(11)
    screen.move(126, 8)
    screen.text_right("> " .. CHAR_NAME[party[active].class])
  end

  -- place label banner (shows briefly on entering a new place / crossing a region)
  if region_label_ticks > 0 then
    -- last_region is "<map_id>:<sub>" — sub is the mainland get_region() value
    -- or empty for non-mainland maps. Map a friendly name per place.
    local PLACE_NAMES = {
      ["1:village"] = "Village Clearing",
      ["1:woods"]   = "Hollow Woods",
      ["1:coast"]   = "Sunward Coast",
      ["2:"]        = "Eastern Reaches",
      ["3:"]        = "Northern Wilds",
      ["4:"]        = "Suno's Domain",
      ["5:"]        = "The Inn",
      ["6:"]        = "Item Shop",
      ["7:"]        = "Cave 1 - The Echoes",
      ["8:"]        = "Cave 2 - Sentinel Grove",
      ["9:"]        = "Cave 3 - Tidewater Grotto",
      ["10:"]       = "Cave 4 - Dune Hall",
      ["11:"]       = "Cave 5 - Frost Vault",
      ["12:"]       = "The Hollow",
      ["13:"]       = "Cave 6 - Locrian Crypt",
      ["14:"]       = "Cave 7 - Suno's Chamber",
      ["17:"]       = "The Saltway Inn",
      ["18:"]       = "Pinehearth Lodge",
      ["19:"]       = "Hall of Resonance",
      ["20:"]       = "Lirael Throne Room",
      ["21:"]       = "The Escape Cave",
      ["22:"]       = "Western Region",
      ["23:"]       = "Lirael Ruins",
      ["24:"]       = "Velthe's Observatory",
      ["25:"]       = "Reya's Cairn",
      ["26:"]       = "The Far Hills",
    }
    local name = PLACE_NAMES[last_region or ""] or ""
    if name ~= "" then
      screen.level(0)
      screen.rect(8, 22, 112, 14); screen.fill()
      screen.level(15)
      screen.rect(8, 22, 112, 14); screen.stroke()
      screen.move(64, 31); screen.text_center(name)
    end
  end

  -- L2 toggle ON → BPM-edit mode; tiny corner strip + hint
  if l2_held then
    screen.level(0)
    screen.rect(0, 0, 90, 10)
    screen.fill()
    screen.level(15)
    screen.move(2, 8)
    screen.text("JRN " .. OVERWORLD_BPM)
    screen.level(8)
    screen.move(88, 8)
    screen.text_right("L2:exit")
  end

  -- DEBUG overlay (toggle in menu)
  if debug_visible then
    if l2_held then
      screen.level(15)
      screen.move(2, 8)
      screen.text("[L2]")
    end
    if (tick - last_input_at) < 60 then
      screen.level(8)
      screen.move(2, 64)
      screen.text(last_input)
    end
  end

  -- inn rest banner — animated zzz, full heal feedback
  if inn_rest_ticks > 0 then
    screen.level(0)
    screen.rect(18, 20, 92, 24)
    screen.fill()
    screen.level(15)
    screen.rect(18, 20, 92, 24)
    screen.stroke()
    screen.move(64, 30)
    screen.text_center("Rested at the inn")
    -- zzz drift
    local zoff = (tick // 3) % 8
    screen.level(11)
    screen.move(96, 32 - zoff)
    screen.text("z")
    screen.move(100, 28 - zoff)
    screen.text("z")
    screen.move(104, 24 - zoff)
    screen.text("z")
    screen.level(8)
    screen.move(64, 39)
    screen.text_center("HP & MP fully restored")
  end

  -- tower-locked banner (shows briefly when player tries to enter without 5 shards)
  if tower_locked_ticks > 0 then
    screen.level(0)
    screen.rect(8, 22, 112, 20)
    screen.fill()
    screen.level(15)
    screen.rect(8, 22, 112, 20)
    screen.stroke()
    screen.move(64, 30)
    screen.text_center("The Tower bars your way.")
    screen.level(8)
    screen.move(64, 38)
    screen.text_center("Gather 5 shards to enter.")
  end

  -- generic event flash banner (chest, campfire heal, equip toast, etc.)
  if CONTENT.flash_ticks > 0 then
    screen.level(0); screen.rect(20, 28, 88, 12); screen.fill()
    screen.level(15); screen.rect(20, 28, 88, 12); screen.stroke()
    screen.move(64, 36); screen.text_center(scrub_text(CONTENT.flash_text or ""))
  end

  -- DAY/NIGHT overlay (Pass 58). Nighttime stipples a sparse dim-pixel
  -- mask across the OVERWORLD only (interiors, ruins, observatory and
  -- caves don't dim). The stipple is deterministic per tile so it
  -- doesn't shimmer. Skipped during scripted scenes (their letterbox
  -- + fade already handle framing). A small "night" indicator in the
  -- top-right corner cues the player.
  if sq_is_night and sq_is_night()
     and (current_map_id == 1 or current_map_id == 2 or current_map_id == 3
          or current_map_id == 22 or current_map_id == 26)
     and not (SCENE and SCENE.active) then
    -- per-pixel scattered dim pattern (every 3rd pixel along a hashed grid)
    for y = 0, 47, 2 do
      for x = (y % 4), 127, 4 do
        screen.level(2); screen.pixel(x, y); screen.fill()
      end
    end
    -- subtle vignette: dim the corners with a thicker edge
    screen.level(3)
    screen.rect(0, 0, 128, 1); screen.fill()
    screen.rect(0, 47, 128, 1); screen.fill()
    -- moon glyph top-right
    screen.level(11); screen.pixel(120, 4); screen.pixel(121, 3)
    screen.pixel(122, 3); screen.pixel(122, 4); screen.pixel(122, 5); screen.fill()
  end

end

-- DAY / NIGHT cycle. ~11 minutes per half-phase at 85 BPM with the
-- 1/4-beat tick rate (3000-tick window). Returns true while the world
-- is in night phase. Used by draw_overworld for the dimming overlay
-- and by night-only NPC visibility closures.
function sq_is_night()
  return ((tick or 0) // 3000) % 2 == 1
end

-- pixel-accurate word wrap using norns screen metrics
local function wrap_text(str, max_px)
  local lines = {}
  local current = ""
  for word in str:gmatch("%S+") do
    local candidate = (#current == 0) and word or (current .. " " .. word)
    if screen.text_extents(candidate) <= max_px then
      current = candidate
    else
      if #current > 0 then table.insert(lines, current) end
      current = word
    end
  end
  if #current > 0 then table.insert(lines, current) end
  return lines
end

-- Maps a party-scene "[Speaker]" tag to a class for sprite lookup.
-- Now includes the recruits so post-join scenes render their portraits too.
local DLG_NAME_TO_CLASS = {
  Alder="bard", Miel="cleric", Strom="warrior", Diegues="mage",
  Sergei="engineer", Paj="mathwiz", Niko="drummer",
}

local function draw_dialogue()
  draw_overworld()
  -- Single dialogue box for ALL dialogue (NPC + scene). Same size
  -- everywhere so the player isn't seeing two different UIs.
  -- Box: y=26..63 = 38px tall.
  --   Header strip y=27..37 (sprite + name + underline)
  --   Body strip   y=39..62 (up to 3 wrapped lines)
  -- Scenes that need actors visible during dialogue must put them at
  -- map rows above where the box covers (cam.y=1 → rows 1-3 visible).
  screen.level(0)
  screen.rect(0, 26, 128, 38)
  screen.fill()
  screen.level(15)
  screen.rect(0, 26, 128, 38)
  screen.stroke()

  -- Parse the current line. If it starts with "[Name]", extract the speaker
  -- (so party-scene lines show the actual character + their sprite, not
  -- "_party_scene").
  local cur = (dlg.lines or {})[dlg.line] or ""
  local sp, rest = cur:match("^%[(%S+)%]%s*(.*)$")
  -- dlg.npc may be nil for narrator-style sequences (campfire memories,
  -- in-line story banter). Fall back to no speaker label in that case.
  local speaker = sp or (dlg.npc and dlg.npc.name) or ""
  if speaker == "_party_scene" then speaker = "" end
  local body = rest or cur
  -- Final safety: if the body still leads with "<speaker>:" (e.g. someone
  -- wrote "[Strom] Strom: ..." or pack didn't catch a stray prefix),
  -- strip it so the name doesn't appear twice (header + body).
  if speaker ~= "" then
    local pat = "^" .. (speaker:gsub("(%W)", "%%%1")) .. ":%s*"
    body = body:gsub(pat, "")
  end

  -- ── HEADER STRIP (y=27..37) — sprite + speaker name + underline ──
  do
    local sprite_fn = nil
    local cls = DLG_NAME_TO_CLASS[speaker]
    if cls and SPRITE_BY_CLASS[cls] then
      sprite_fn = SPRITE_BY_CLASS[cls]
    elseif NPC_SPRITES and NPC_SPRITES[speaker] then
      sprite_fn = NPC_SPRITES[speaker]
    end
    local name_x = 4
    if sprite_fn then
      local saved = player.facing
      player.facing = "down"
      local bob = ((tick % 6) < 3) and 0 or 1
      sprite_fn(2, 28 - bob)
      if (tick % 4) < 2 then
        screen.level(15); screen.pixel(11, 32 - bob); screen.fill()
      end
      player.facing = saved
      name_x = 13
    end
    screen.level(15)
    screen.move(name_x, 34)
    screen.text(speaker)
    screen.level(4)
    screen.move(2, 37); screen.line(126, 37); screen.stroke()
  end

  -- ── BODY STRIP (y=39..62) ──
  -- 3 lines max. Default font (8 tall) fits 3 lines at y=46/54/62; the
  -- compact font (6 tall) is used when wrap count exceeds 3 with default
  -- font, still capped at 3 lines.
  --
  -- FF-style typewriter. Characters reveal at TYPEWRITER_CPT chars/tick.
  -- 3.0 cpt @ 20fps = 60 chars/sec — fast enough that the reveal feels
  -- snappy ("characters speak quickly") without being instant. A single
  -- A-press still snaps to fully-revealed; a second A advances.
  -- (Previous value of 0.85 cpt = 17 chars/sec was glacial — most lines
  --  took 4+ seconds, which read as "cut off and moving really slow".)
  if not dlg.line_start_tick then dlg.line_start_tick = tick end
  local TYPEWRITER_CPT = 4.0   -- ~80 chars/sec, snappy
  local age = tick - (dlg.line_start_tick or tick)
  local total_chars = #body
  local revealed = math.min(total_chars, math.floor(age * TYPEWRITER_CPT))
  if dlg.snap_to_complete then revealed = total_chars end
  dlg.complete = (revealed >= total_chars)
  local visible_body = body:sub(1, revealed)
  screen.level(13)
  local body_x = 2
  -- Pre-compute the FULL line count so font choice doesn't hop mid-
  -- reveal. (Otherwise a 4-line message would suddenly switch to the
  -- compact font as the typewriter crossed the 3-line threshold.)
  local lines = wrap_text(visible_body, 124 - body_x)
  local full_lines = wrap_text(body, 124 - body_x)
  if #full_lines > 3 then
    screen.font_face(25); screen.font_size(6)
    local lines_compact = wrap_text(visible_body, 124 - body_x)
    for i = 1, math.min(3, #lines_compact) do
      screen.move(body_x, 45 + i * 6)
      screen.text(lines_compact[i])
    end
    screen.font_face(1); screen.font_size(8)
  else
    for i = 1, math.min(3, #lines) do
      screen.move(body_x, 38 + i * 8)
      screen.text(lines[i])
    end
  end
  -- advance prompt — only flickers once the full line is revealed.
  if dlg.complete and (tick % 6) < 4 then
    screen.level(15)
    screen.move(122, 62)
    screen.text("v")
  end
end

-- ============================================================ DRAWING — BATTLE

local DRAW_ENEMY = {}

-- Practice dummy: a stout straw figure with concentric target rings.
-- Drawn calmly (tiny sway only) so it reads as "harmless" rather than alive.
function DRAW_ENEMY.dummy(cx, cy)
  local sway = math.sin(tick / 6) * 0.5
  -- post / pole
  screen.level(4)
  screen.move(cx + sway, cy + 8)
  screen.line(cx + sway, cy + 14)
  screen.stroke()
  -- straw body (rounded rectangle-ish)
  screen.level(8)
  screen.rect(cx - 6 + sway, cy - 6, 12, 14)
  screen.fill()
  -- target rings on the body
  screen.level(0)
  screen.circle(cx + sway, cy, 5)
  screen.stroke()
  screen.level(15)
  screen.circle(cx + sway, cy, 3)
  screen.fill()
  screen.level(0)
  screen.circle(cx + sway, cy, 1)
  screen.fill()
  -- arms (straw tufts)
  screen.level(6)
  screen.move(cx - 6 + sway, cy - 2); screen.line(cx - 9 + sway, cy + 1); screen.stroke()
  screen.move(cx + 6 + sway, cy - 2); screen.line(cx + 9 + sway, cy + 1); screen.stroke()
  -- friendly head: simple circle with two dots
  screen.level(10)
  screen.circle(cx + sway, cy - 9, 3)
  screen.fill()
  screen.level(0)
  screen.pixel(math.floor(cx - 1 + sway), math.floor(cy - 10)); screen.fill()
  screen.pixel(math.floor(cx + 1 + sway), math.floor(cy - 10)); screen.fill()
end

function DRAW_ENEMY.slime(cx, cy)
  local pulse = (tick % 4) / 4
  local r = 6 + math.floor(math.sin(pulse * math.pi * 2) * 1.5)
  screen.level(8)
  screen.circle(cx, cy, r)
  screen.fill()
  screen.level(0)
  screen.circle(cx - 1, cy - 1, 1)
  screen.fill()
end

function DRAW_ENEMY.bat(cx, cy)
  local wing = math.sin((tick % 2) / 2 * math.pi * 2) * 3
  screen.level(12)
  screen.circle(cx, cy, 2)
  screen.fill()
  screen.level(8)
  screen.move(cx - 9, cy - wing)
  screen.line(cx - 4, cy - 1)
  screen.line(cx - 1, cy + 1)
  screen.line(cx + 2, cy - 1)
  screen.line(cx + 6, cy - wing)
  screen.stroke()
end

function DRAW_ENEMY.mushroom(cx, cy)
  -- cap
  screen.level(11)
  screen.circle(cx, cy - 2, 5)
  screen.fill()
  -- stem
  screen.level(7)
  screen.rect(cx - 2, cy + 1, 4, 5)
  screen.fill()
  -- spots, alternating phase
  if (tick % 8) < 4 then
    screen.level(0)
    screen.pixel(cx - 3, cy - 3)
    screen.pixel(cx + 2, cy - 1)
  else
    screen.level(0)
    screen.pixel(cx - 1, cy - 4)
    screen.pixel(cx + 3, cy - 2)
  end
end

function DRAW_ENEMY.wisp(cx, cy)
  local pulse = (tick % 6) / 6
  -- outer halo flickers brightness
  screen.level(math.floor(3 + 3 * math.sin(pulse * math.pi * 2)))
  screen.circle(cx, cy, 5)
  screen.fill()
  -- core
  screen.level(15)
  screen.circle(cx, cy, 2)
  screen.fill()
  -- spark pixels orbit
  if (tick % 4) < 2 then
    screen.level(10)
    screen.pixel(cx - 4, cy - 3)
    screen.pixel(cx + 3, cy + 2)
  else
    screen.level(10)
    screen.pixel(cx + 4, cy - 2)
    screen.pixel(cx - 3, cy + 3)
  end
end

function DRAW_ENEMY.wolf(cx, cy)
  -- body
  screen.level(8)
  screen.rect(cx - 6, cy - 1, 12, 4)
  screen.fill()
  -- head
  screen.rect(cx + 4, cy - 3, 4, 3)
  screen.fill()
  -- ears
  screen.pixel(cx + 5, cy - 4)
  screen.pixel(cx + 7, cy - 4)
  -- tail (line back-and-up)
  screen.move(cx - 6, cy)
  screen.line(cx - 9, cy - 2)
  screen.stroke()
  -- legs
  screen.rect(cx - 5, cy + 3, 1, 2)
  screen.fill()
  screen.rect(cx - 1, cy + 3, 1, 2)
  screen.fill()
  screen.rect(cx + 5, cy + 3, 1, 2)
  screen.fill()
  -- eye
  screen.level(0)
  screen.pixel(cx + 6, cy - 2)
end

function DRAW_ENEMY.echo(cx, cy)
  -- big amorphous body that breathes
  local pulse = math.sin((tick % 8) / 8 * math.pi * 2)
  local r = 9 + math.floor(pulse * 1.5)
  screen.level(6)
  screen.circle(cx, cy, r)
  screen.fill()
  screen.level(2)
  screen.circle(cx, cy, math.max(1, r - 2))
  screen.fill()
  -- multiple eyes pulsing in 3-phase cycle
  local eye_phase = math.floor(tick / 4) % 3
  screen.level(15)
  if eye_phase == 0 then
    screen.rect(cx - 3, cy - 2, 2, 1)
    screen.fill()
    screen.pixel(cx + 2, cy + 1)
  elseif eye_phase == 1 then
    screen.rect(cx + 1, cy - 3, 2, 1)
    screen.fill()
    screen.pixel(cx - 4, cy + 2)
  else
    screen.pixel(cx, cy + 2)
    screen.pixel(cx + 4, cy - 1)
    screen.pixel(cx - 1, cy + 3)
  end
end

function DRAW_ENEMY.sprite(cx, cy)
  -- tiny darting magical creature: bright core + 4 trailing pixels
  local pulse = (tick % 6) / 6
  local r = 2 + math.floor(math.sin(pulse * math.pi * 2) * 1)
  screen.level(15)
  screen.circle(cx, cy, r)
  screen.fill()
  screen.level(8)
  screen.pixel(cx - 4, cy - 2)
  screen.pixel(cx + 4, cy + 1)
  screen.pixel(cx - 2, cy + 3)
  screen.pixel(cx + 3, cy - 3)
end

function DRAW_ENEMY.treant(cx, cy)
  -- A walking tree: wide gnarled trunk + two branch-arms + leafy crown +
  -- glowing eyes peering out of a face carved into the bark. Subtle sway.
  local sway = math.floor(math.sin(tick / 8) * 1)
  -- root base (splayed roots)
  screen.level(3)
  screen.move(cx - 7, cy + 11); screen.line(cx, cy + 7); screen.line(cx + 7, cy + 11)
  screen.close(); screen.fill()
  -- gnarled trunk (wider middle than top)
  screen.level(5)
  screen.rect(cx - 4 + sway, cy - 2, 8, 9); screen.fill()
  screen.level(3)
  screen.move(cx - 4 + sway, cy + 7); screen.line(cx + 4 + sway, cy + 7); screen.stroke()
  -- bark grooves (vertical lines on trunk)
  screen.level(3)
  screen.move(cx - 2 + sway, cy - 1); screen.line(cx - 2 + sway, cy + 6); screen.stroke()
  screen.move(cx + 2 + sway, cy - 1); screen.line(cx + 2 + sway, cy + 6); screen.stroke()
  -- branch-arms (one bent up, one down — like an Ent stride)
  screen.level(5)
  screen.move(cx - 4 + sway, cy);     screen.line(cx - 8 + sway, cy - 3); screen.stroke()
  screen.move(cx - 8 + sway, cy - 3); screen.line(cx - 9 + sway, cy);     screen.stroke()
  screen.move(cx + 4 + sway, cy + 1); screen.line(cx + 8 + sway, cy + 4); screen.stroke()
  screen.move(cx + 8 + sway, cy + 4); screen.line(cx + 9 + sway, cy + 1); screen.stroke()
  -- finger twigs at each hand
  screen.level(3)
  screen.pixel(cx - 9 + sway, cy - 1); screen.pixel(cx - 10 + sway, cy + 1); screen.fill()
  screen.pixel(cx + 9 + sway, cy + 5); screen.pixel(cx + 10 + sway, cy + 3); screen.fill()
  -- leafy crown (rounded blob with little leaf clusters)
  screen.level(7)
  screen.circle(cx + sway, cy - 6, 5); screen.fill()
  screen.level(11)
  screen.pixel(cx - 3 + sway, cy - 8); screen.pixel(cx + 4 + sway, cy - 7)
  screen.pixel(cx - 1 + sway, cy - 10); screen.pixel(cx + 2 + sway, cy - 9); screen.fill()
  screen.level(3)  -- shadow underside of crown
  screen.move(cx - 4 + sway, cy - 3); screen.line(cx + 4 + sway, cy - 3); screen.stroke()
  -- carved face: hollow eyes (glow) + mouth slit
  local lit = (tick % 30) < 22
  screen.level(lit and 13 or 8)
  screen.pixel(cx - 2 + sway, cy + 1); screen.pixel(cx + 2 + sway, cy + 1); screen.fill()
  screen.level(0)
  screen.move(cx - 2 + sway, cy + 4); screen.line(cx + 2 + sway, cy + 4); screen.stroke()
end

function DRAW_ENEMY.sentinel(cx, cy)
  -- tall guardian with antlers, slowly swaying
  local sway = math.floor(math.sin((tick % 32) / 32 * math.pi * 2) * 1.5)
  -- body
  screen.level(8)
  screen.rect(cx - 4 + sway, cy - 4, 8, 12)
  screen.fill()
  -- antlers
  screen.level(11)
  screen.move(cx - 5 + sway, cy - 4)
  screen.line(cx - 7 + sway, cy - 8)
  screen.move(cx - 5 + sway, cy - 4)
  screen.line(cx - 4 + sway, cy - 7)
  screen.move(cx + 4 + sway, cy - 4)
  screen.line(cx + 6 + sway, cy - 8)
  screen.move(cx + 4 + sway, cy - 4)
  screen.line(cx + 3 + sway, cy - 7)
  screen.stroke()
  -- glowing eyes (2-phase)
  local lit = (tick % 16) < 12
  screen.level(lit and 15 or 4)
  screen.pixel(cx - 2 + sway, cy - 1)
  screen.pixel(cx + 2 + sway, cy - 1)
end

function DRAW_ENEMY.crab(cx, cy)
  -- low oval body + 2 claws + skitter offset
  local skitter = (tick % 4) < 2 and -1 or 1
  screen.level(10)
  screen.rect(cx - 4 + skitter, cy, 8, 4)
  screen.fill()
  -- claws (small triangles to either side)
  screen.move(cx - 6 + skitter, cy + 2)
  screen.line(cx - 8 + skitter, cy)
  screen.line(cx - 4 + skitter, cy)
  screen.close()
  screen.fill()
  screen.move(cx + 6 + skitter, cy + 2)
  screen.line(cx + 8 + skitter, cy)
  screen.line(cx + 4 + skitter, cy)
  screen.close()
  screen.fill()
  -- eyes
  screen.level(0)
  screen.pixel(cx - 1 + skitter, cy + 1)
  screen.pixel(cx + 2 + skitter, cy + 1)
end

function DRAW_ENEMY.manta(cx, cy)
  -- diamond/triangle gliding shape, slow swoop
  local sw = math.floor(math.sin((tick % 12) / 12 * math.pi * 2) * 2)
  screen.level(8)
  screen.move(cx, cy - 4)
  screen.line(cx - 7, cy + sw)
  screen.line(cx, cy + 4)
  screen.line(cx + 7, cy + sw)
  screen.close()
  screen.fill()
  -- tail
  screen.move(cx, cy + 4)
  screen.line(cx, cy + 7)
  screen.stroke()
  -- eyespots
  screen.level(0)
  screen.pixel(cx - 2, cy)
  screen.pixel(cx + 2, cy)
end

function DRAW_ENEMY.tide(cx, cy)
  -- broad wave-creature with multiple peaks, slow churning
  local phase = (tick % 16) / 16 * math.pi * 2
  screen.level(5)
  -- low wide body
  screen.rect(cx - 10, cy + 1, 20, 6)
  screen.fill()
  -- wave peaks
  screen.level(8)
  for i = -2, 2 do
    local px = cx + i * 4
    local h = 4 + math.floor(math.sin(phase + i * 0.7) * 2)
    screen.move(px - 2, cy + 1)
    screen.line(px, cy + 1 - h)
    screen.line(px + 2, cy + 1)
    screen.close()
    screen.fill()
  end
  -- shimmering eyes
  if (tick % 8) < 6 then
    screen.level(15)
    screen.pixel(cx - 3, cy + 4)
    screen.pixel(cx + 3, cy + 4)
  end
end

function DRAW_ENEMY.scorpion(cx, cy)
  -- low body + curled tail + claws
  screen.level(10)
  screen.rect(cx - 4, cy + 1, 8, 3)
  screen.fill()
  -- claws (forward)
  screen.move(cx - 6, cy + 1); screen.line(cx - 8, cy - 1); screen.line(cx - 4, cy + 1); screen.close(); screen.fill()
  screen.move(cx + 6, cy + 1); screen.line(cx + 8, cy - 1); screen.line(cx + 4, cy + 1); screen.close(); screen.fill()
  -- segmented tail curling up over the back
  screen.level(13)
  screen.pixel(cx + 1, cy)
  screen.pixel(cx + 2, cy - 1)
  screen.pixel(cx + 1, cy - 2)
  screen.pixel(cx, cy - 3)
  screen.pixel(cx - 1, cy - 2)
  -- stinger
  screen.level(15)
  screen.pixel(cx - 2, cy - 3)
end

function DRAW_ENEMY.spectre(cx, cy)
  -- ghostly tall figure with wavy bottom
  local sw = math.floor(math.sin((tick % 16) / 16 * math.pi * 2) * 1)
  screen.level(7)
  -- body
  screen.move(cx - 4 + sw, cy - 6)
  screen.line(cx + 4 + sw, cy - 6)
  screen.line(cx + 5 + sw, cy + 5)
  screen.line(cx + 2 + sw, cy + 6)
  screen.line(cx + sw,     cy + 5)
  screen.line(cx - 2 + sw, cy + 6)
  screen.line(cx - 5 + sw, cy + 5)
  screen.close()
  screen.fill()
  -- glowing eyes
  if (tick % 12) < 8 then
    screen.level(15)
    screen.pixel(cx - 2 + sw, cy - 3)
    screen.pixel(cx + 2 + sw, cy - 3)
  end
end

function DRAW_ENEMY.dunerider(cx, cy)
  -- large mounted figure: body of sand-mount + rider above
  local phase = (tick % 16) / 16 * math.pi * 2
  -- mount body (low broad)
  screen.level(11)
  screen.rect(cx - 9, cy + 2, 18, 5)
  screen.fill()
  -- mount head
  screen.move(cx + 9, cy + 2)
  screen.line(cx + 12, cy + 4)
  screen.line(cx + 9, cy + 6)
  screen.close()
  screen.fill()
  -- legs (two pairs)
  screen.rect(cx - 6, cy + 7, 1, 2); screen.fill()
  screen.rect(cx - 2, cy + 7, 1, 2); screen.fill()
  screen.rect(cx + 4, cy + 7, 1, 2); screen.fill()
  screen.rect(cx + 7, cy + 7, 1, 2); screen.fill()
  -- rider on top
  screen.level(5)
  screen.rect(cx - 1, cy - 4, 4, 6)
  screen.fill()
  -- rider head
  screen.level(13)
  screen.rect(cx, cy - 6, 2, 2)
  screen.fill()
  -- spear with phase
  screen.level(15)
  screen.move(cx + 3, cy - 4)
  screen.line(cx + 7 + math.floor(math.sin(phase) * 1), cy - 8)
  screen.stroke()
  -- eyes
  if (tick % 8) < 6 then
    screen.level(0)
    screen.pixel(cx - 4, cy + 4)
    screen.pixel(cx + 1, cy + 4)
  end
end

-- Cave 5 enemies (Northern Wilds)
function DRAW_ENEMY.yeti(cx, cy)
  -- huge furred shape, two arms
  screen.level(15)
  screen.rect(cx - 14, cy - 16, 28, 28)  -- white furred body
  screen.fill()
  screen.level(11)
  -- arms
  screen.rect(cx - 18, cy - 8, 4, 14)
  screen.fill()
  screen.rect(cx + 14, cy - 8, 4, 14)
  screen.fill()
  -- darker face hollow
  screen.level(2)
  screen.rect(cx - 6, cy - 10, 12, 6)
  screen.fill()
  -- glowing eyes
  screen.level(15)
  screen.pixel(cx - 3, cy - 7)
  screen.pixel(cx + 2, cy - 7)
  -- horn tusks
  screen.level(13)
  screen.move(cx - 4, cy - 4); screen.line(cx - 6, cy); screen.stroke()
  screen.move(cx + 3, cy - 4); screen.line(cx + 5, cy); screen.stroke()
end

function DRAW_ENEMY.frostwisp(cx, cy)
  -- shimmering ice diamond + drift
  local d = (tick // 4) % 8
  screen.level(15)
  screen.move(cx,     cy - 12 + d)
  screen.line(cx + 8, cy)
  screen.line(cx,     cy + 12 + d)
  screen.line(cx - 8, cy)
  screen.close()
  screen.fill()
  -- inner shadow
  screen.level(7)
  screen.move(cx,     cy - 6 + d)
  screen.line(cx + 4, cy)
  screen.line(cx,     cy + 6 + d)
  screen.line(cx - 4, cy)
  screen.close()
  screen.fill()
  -- core
  screen.level(15)
  screen.pixel(cx, cy)
  -- snowflakes around
  screen.level(13)
  screen.pixel(cx - 12, cy - 4 + d)
  screen.pixel(cx + 13, cy + 6 - d)
end

-- The First Chord — post-endgame superboss. A shifting cluster of
-- void-pixels that rearrange themselves every few ticks (no fixed
-- form), with a bright central "kernel" that pulses like a heartbeat.
-- The whole thing reads as a thing too dissonant to settle.
function DRAW_ENEMY.firstchord(cx, cy)
  -- outer void halo (dark)
  screen.level(2); screen.rect(cx - 18, cy - 14, 36, 28); screen.fill()
  -- shifting field of bright pixels (8 rotating positions)
  local seed = math.floor(tick / 3) % 8
  for i = 0, 11 do
    local a = (i / 12) * math.pi * 2 + (seed * 0.3)
    local r = 10 + (i % 3) * 3
    local px = math.floor(cx + math.cos(a) * r)
    local py = math.floor(cy + math.sin(a) * (r * 0.6))
    screen.level((i + seed) % 4 == 0 and 15 or 8)
    screen.pixel(px, py); screen.fill()
  end
  -- middle cluster (bright)
  local pulse = ((tick % 16) < 8) and 13 or 15
  screen.level(pulse); screen.rect(cx - 4, cy - 4, 9, 9); screen.fill()
  -- inner kernel (heartbeat)
  screen.level(0); screen.rect(cx - 1, cy - 1, 3, 3); screen.fill()
  screen.level(15); screen.pixel(cx, cy); screen.fill()
  -- vertical "rip" through center (a glitch line)
  if (tick % 32) < 4 then
    screen.level(15)
    screen.rect(cx, cy - 14, 1, 28); screen.fill()
  end
end

-- Strom, the academy boss — heavy warrior with a slab hammer. Stands
-- ~28 tall x ~24 wide; raises the hammer 1 px on alternate ticks so
-- the silhouette reads as menacing rather than static.
function DRAW_ENEMY.strom(cx, cy)
  local hammer_lift = ((tick % 16) < 8) and 0 or 1
  -- legs (dark armored boots)
  screen.level(3)
  screen.rect(cx - 6, cy + 8, 4, 5); screen.fill()
  screen.rect(cx + 2, cy + 8, 4, 5); screen.fill()
  -- chestplate (mid-tone iron)
  screen.level(6)
  screen.rect(cx - 8, cy - 6, 16, 14); screen.fill()
  -- chestplate highlight strip (top edge)
  screen.level(11); screen.rect(cx - 8, cy - 6, 16, 1); screen.fill()
  -- belt + buckle
  screen.level(2); screen.rect(cx - 8, cy + 4, 16, 2); screen.fill()
  screen.level(13); screen.pixel(cx - 1, cy + 5); screen.pixel(cx, cy + 5); screen.fill()
  -- pauldrons (shoulder armor flares)
  screen.level(7); screen.rect(cx - 11, cy - 5, 4, 6); screen.fill()
  screen.level(7); screen.rect(cx + 7,  cy - 5, 4, 6); screen.fill()
  -- arms holding the hammer (right arm raised across body)
  screen.level(5); screen.rect(cx - 10, cy - 1, 3, 7); screen.fill()
  screen.level(5); screen.rect(cx + 2,  cy - 6 - hammer_lift, 3, 9); screen.fill()
  -- helmet base
  screen.level(5); screen.rect(cx - 6, cy - 14, 12, 8); screen.fill()
  -- helmet top crest (a single ridge)
  screen.level(11); screen.rect(cx - 1, cy - 16, 2, 2); screen.fill()
  -- helmet visor slit
  screen.level(0); screen.rect(cx - 5, cy - 10, 10, 2); screen.fill()
  -- glowing visor eyes
  screen.level(15)
  screen.pixel(cx - 3, cy - 9); screen.pixel(cx + 2, cy - 9); screen.fill()
  -- HAMMER on his right shoulder (handle going up-right; head at top)
  -- handle
  screen.level(4)
  screen.rect(cx + 3, cy - 14 - hammer_lift, 2, 8); screen.fill()
  -- head (slab block)
  screen.level(7)
  screen.rect(cx,     cy - 20 - hammer_lift, 8, 6); screen.fill()
  screen.level(11); screen.rect(cx, cy - 20 - hammer_lift, 8, 1); screen.fill()
  screen.level(2);  screen.rect(cx, cy - 15 - hammer_lift, 8, 1); screen.fill()
  -- rivet marks on the hammer head
  screen.level(13)
  screen.pixel(cx + 1, cy - 18 - hammer_lift)
  screen.pixel(cx + 6, cy - 18 - hammer_lift); screen.fill()
end

