    screen.move(cx - 6, cy);  screen.line(cx - 18, cy - 6); screen.line(cx - 6, cy + 4); screen.close(); screen.fill()
    screen.move(cx + 6, cy);  screen.line(cx + 18, cy - 6); screen.line(cx + 6, cy + 4); screen.close(); screen.fill()
  else
    screen.move(cx - 6, cy);  screen.line(cx - 16, cy + 6); screen.line(cx - 6, cy + 4); screen.close(); screen.fill()
